#include <stdio.h>
#include <stdint.h>

static inline int64_t ceil_div(int64_t a, int64_t b) {
    return (a + b - 1) / b;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int64_t H, X, Y1, Y2, K;
        scanf("%lld %lld %lld %lld %lld", &H, &X, &Y1, &Y2, &K);
        int64_t gun_hits = ceil_div(H, X);
        int64_t laser_hits;
        int64_t hits_if_all_y1 = ceil_div(H, Y1);
        if (hits_if_all_y1 <= K) {
            laser_hits = hits_if_all_y1;
        } else {
            int64_t damage_first = K * Y1;
            int64_t remaining = H > damage_first ? H - damage_first : 0;
            laser_hits = K + ceil_div(remaining, Y2);
        }
        int64_t ans = gun_hits < laser_hits ? gun_hits : laser_hits;
        printf("%lld\n", ans);
    }
    return 0;
}

