import java.io.*;
import java.util.*;

public class Main {
    private static long ceilDiv(long a, long b) {
        return (a + b - 1) / b;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder sb = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            long H = Long.parseLong(st.nextToken());
            long X = Long.parseLong(st.nextToken());
            long Y1 = Long.parseLong(st.nextToken());
            long Y2 = Long.parseLong(st.nextToken());
            long K = Long.parseLong(st.nextToken());
            long gunHits = ceilDiv(H, X);
            long laserHits;
            long hitsAllY1 = ceilDiv(H, Y1);
            if (hitsAllY1 <= K) {
                laserHits = hitsAllY1;
            } else {
                long damageFirst = K * Y1;
                long remaining = H > damageFirst ? H - damageFirst : 0;
                laserHits = K + ceilDiv(remaining, Y2);
            }
            sb.append(Math.min(gunHits, laserHits)).append('\n');
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def ceil_div(a, b):
    return (a + b - 1) // b

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        H = int(next(it)); X = int(next(it)); Y1 = int(next(it)); Y2 = int(next(it)); K = int(next(it))
        gun_hits = ceil_div(H, X)
        hits_all_y1 = ceil_div(H, Y1)
        if hits_all_y1 <= K:
            laser_hits = hits_all_y1
        else:
            damage_first = K * Y1
            remaining = H - damage_first if H > damage_first else 0
            laser_hits = K + ceil_div(remaining, Y2)
        out_lines.append(str(min(gun_hits, laser_hits)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

